	if !lim.Allow("b") {
		t.Fatal("key 'b' second request should be allowed")
	}
	if lim.Allow("b") {
		t.Fatal("key 'b' third request should be denied")
	}
}

func TestReset(t *testing.T) {
	clock := NewTestClock(epoch)
	lim := NewLimiter(Config{Rate: 2, Window: time.Second}, clock)

	// Exhaust key "x".
